func LookupMethod(method string) (MethodInfo, bool) {
	info, ok := methodRegistry[method]
	return info, ok
}

func AllMethods() []MethodInfo {
	methods := make([]MethodInfo, 0, len(methodRegistry))
	for _, info := range methodRegistry {
		methods = append(methods, info)
	}
	sortMethodInfo(methods)
	return methods
}

func sortMethodInfo(methods []MethodInfo) {
	for i := 1; i < len(methods); i++ {
		for j := i; j > 0 && methods[j-1].Method > methods[j].Method; j-- {
			methods[j-1], methods[j] = methods[j], methods[j-1]
		}
	}
}
